@namespace Lumeo

<div class="@CssClass" role="group" aria-label="@AriaLabel" @attributes="AdditionalAttributes">
    @ChildContent
</div>

@code {
    /// <summary>The buttons (or button-like elements, e.g. link-buttons or Toggle) to render as a single visually-joined group.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }
    /// <summary>Additional CSS classes merged onto the root <c>role="group"</c> element.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Layout direction: <c>Horizontal</c> (default) joins children left-to-right with rounded end-caps; <c>Vertical</c> stacks them top-to-bottom.</summary>
    [Parameter] public Lumeo.Orientation Orientation { get; set; } = Lumeo.Orientation.Horizontal;
    /// <summary>
    /// Accessible name for the button group (exposes it to AT as a named
    /// <c>role="group"</c>). Roving tabindex is intentionally NOT forced here —
    /// a ButtonGroup commonly wraps independent actions that each need their own
    /// tab stop; use <c>Toolbar</c> for single-tab-stop/arrow-key navigation. (#270)
    /// </summary>
    [Parameter] public string? AriaLabel { get; set; }
    /// <summary>Unmatched attributes splatted onto the root <c>role="group"</c> element.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge(
        Orientation == Lumeo.Orientation.Horizontal ? HorizontalClasses : VerticalClasses,
        Class);

    // Horizontal: first child gets left-rounded, last gets right-rounded, middle ones square.
    // -ms-px collapses the shared border between adjacent children.
    // Selectors target every direct child (`&>*`) — not just `button` — so link-buttons
    // (<Button Href=...> -> <a>), AsChild/Slot, and Toggle children all collapse/round
    // correctly, and the :first-child/:last-child index is computed over the SAME set that
    // is styled (a non-button first/last child no longer shifts the rounding). (#111, #200)
    private const string HorizontalClasses =
        "inline-flex flex-row " +
        "[&>*:not(:first-child)]:rounded-s-none " +
        "[&>*:not(:last-child)]:rounded-e-none " +
        "[&>*:not(:first-child)]:-ms-px " +
        "[&>*:not(:first-child)]:border-s-border/40";

    // Vertical: first child gets top-rounded, last gets bottom-rounded, middle ones square.
    // -mt-px collapses the shared border between adjacent children. See HorizontalClasses
    // for why these target every direct child (`&>*`) rather than `button`. (#111, #200)
    private const string VerticalClasses =
        "inline-flex flex-col " +
        "[&>*:not(:first-child)]:rounded-t-none " +
        "[&>*:not(:last-child)]:rounded-b-none " +
        "[&>*:not(:first-child)]:-mt-px " +
        "[&>*:not(:first-child)]:border-t-border/40";

}
